interface Props {
  filters: any;
  setFilters: (f: any) => void;
}

export default function FilterPanel({ filters, setFilters }: Props) {
  const handleChange = (e: any) => {
    setFilters({ ...filters, [e.target.name]: e.target.value });
  };

  return (
    <div className="bg-white p-4 rounded shadow grid grid-cols-4 gap-4">
      <input
        name="disease"
        placeholder="Disease"
        onChange={handleChange}
        className="input"
      />

      <input
        name="location"
        placeholder="Location"
        onChange={handleChange}
        className="input"
      />

      <input
        name="startDate"
        type="date"
        onChange={handleChange}
        className="input"
      />

      <input
        name="endDate"
        type="date"
        onChange={handleChange}
        className="input"
      />

      <input
        name="ageGroup"
        placeholder="Age Group (e.g. 20-30)"
        onChange={handleChange}
        className="input col-span-2"
      />
    </div>
  );
}